SELECT sector_performance_index
FROM sector_analysis
WHERE sector_name = 'Mining';

SELECT average_market_cap
FROM sector_analysis
WHERE sector_name = 'Industrial Metals';

SELECT average_market_cap
FROM sector_analysis
WHERE sector_name = 'Mining';

SELECT company_name
FROM companies
WHERE sector = 'Industrial Metals & Minerals Industry';

SELECT company_name
FROM companies
WHERE founded_year < 1980 AND sector = 'Industrial Metals';

SELECT sector_name
FROM sector_analysis
ORDER BY sector_performance_index DESC;

SELECT forecast_date, forecast_value
FROM financial_forecasts
WHERE metric_name = 'Dividend Yield';

SELECT AVG(CAST(REPLACE(average_dividend_yield, '%', '') AS REAL) / 100) AS average_dividend_yield_decimal
FROM sector_analysis
WHERE sector_id = 1;
